function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = s.length;

    // 1. Count frequencies and record first appearance index for each vowel
    const freq = new Map();
    const firstIndex = new Map();

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Update frequency
            freq.set(char, (freq.get(char) || 0) + 1);
            // Record first index if not already recorded
            if (!firstIndex.has(char)) {
                firstIndex.set(char, i);
            }
        }
    }

    // 2. Extract all vowels and their properties
    // We need to sort them based on:
    // 1. Frequency (descending)
    // 2. First appearance index (ascending) - for tie-breaking

    const vowelInfo = [];
    for (const char of ['a', 'e', 'i', 'o', 'u']) {
        if (freq.has(char)) {
            vowelInfo.push({
                char: char,
                frequency: freq.get(char),
                firstPos: firstIndex.get(char)
            });
        }
    }

    // Sort the vowels
    vowelInfo.sort((a, b) => {
        // Primary sort: Frequency (descending)
        if (a.frequency !== b.frequency) {
            return b.frequency - a.frequency;
        }
        // Secondary sort: First appearance position (ascending)
        return a.firstPos - b.firstPos;
    });

    // Get the sequence of sorted vowels based on the rules
    // We need to construct the list of *all* vowels in the order they should appear
    const sortedVowelsSequence = [];
    for (const info of vowelInfo) {
        const char = info.char;
        const count = freq.get(char);
        for (let k = 0; k < count; k++) {
            sortedVowelsSequence.push(char);
        }
    }

    // 3. Reconstruct the string
    const resultArr = s.split('');
    let sortedVowelIndex = 0;

    for (let i = 0; i < n; i++) {
        if (vowels.has(s[i])) {
            // This position originally held a vowel. Replace it with the next vowel from the sorted sequence.
            resultArr[i] = sortedVowelsSequence[sortedVowelIndex];
            sortedVowelIndex++;
        }
    }

    return resultArr.join('');
}

