from collections import Counter

def solve(s: str) -> str:
    vowels = {'a', 'e', 'i', 'o', 'u'}
    n = len(s)

    # 1. Count frequencies and record first appearance index for each vowel
    freq = Counter()
    first_index = {}

    for i in range(n):
        char = s[i]
        if char in vowels:
            freq[char] += 1
            if char not in first_index:
                first_index[char] = i

    # 2. Determine the order of vowels based on sorting criteria
    # Criteria:
    # 1. Frequency (descending)
    # 2. First appearance index (ascending) - for tie-breaking

    # Collect vowels that appeared
    present_vowels = list(freq.keys())

    # Sort the vowels
    # Key for sorting: (-frequency, first_index)
    def sort_key(vowel):
        return (-freq[vowel], first_index[vowel])

    sorted_vowels_chars = sorted(present_vowels, key=sort_key)

    # Construct the sequence of all vowels in the required order
    sorted_vowels_sequence = []
    for char in sorted_vowels_chars:
        count = freq[char]
        sorted_vowels_sequence.extend([char] * count)

    # 3. Reconstruct the string
    result_list = list(s)
    sorted_vowel_index = 0

    for i in range(n):
        if s[i] in vowels:
            # This position originally held a vowel. Replace it with the next vowel from the sorted sequence.
            result_list[i] = sorted_vowels_sequence[sorted_vowel_index]
            sorted_vowel_index += 1

    return "".join(result_list)
